    <file>services/geminiService.ts</file>
    <content><![CDATA[import { GoogleGenerativeAI } from "@google/generative-ai";
import {
  UpcomingMatch,
  FetchedMatchData,
  AnalysisResult,
  AnalysisRequest,
  ParlayRequest,
  ParlayRecommendation,
  CleanedMatchData,
} from "../types";
import { analyzeMatch } from "../helpers";
import { PARLAY_SYSTEM_PROMPT } from "../constants";

const API_KEY = process.env.GOOGLE_API_KEY;

if (!API_KEY) {
  throw new Error("GOOGLE_API_KEY is not defined in environment variables");
}

const genAI = new GoogleGenerativeAI(API_KEY);

const cleanJson = (input: string): string => {
  const openBracketIndex = input.indexOf("[");
  const closeBracketIndex = input.lastIndexOf("]");
  if (openBracketIndex === -1 || closeBracketIndex === -1) {
    return "[]";
  }
  return input.substring(openBracketIndex, closeBracketIndex + 1);
};

export const fetchUpcomingMatches = async (
  sport: string,
  country: string,
  date: string,
  league: string
): Promise<FetchedMatchData[]> => {
  try {
    const model = genAI.getGenerativeModel({
      model: "gemini-pro",
      safetySettings: [
        { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_NONE" },
        { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_NONE" },
        { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_NONE" },
        { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_NONE" },
      ],
      generationConfig: {
        maxOutputTokens: 2048,
        temperature: 0.1,
      },
    });

    const prompt = `You are a sports analyst.  
    Given the current date, sport, country, and league, provide a JSON array containing upcoming matches. 
    Each match should include:
        - date: The date of the match.
        - time: The time of the match.
        - homeTeam: The name of the home team.
        - awayTeam: The name of the away team.
        - league: The name of the league.
        - odds: {
            homeWin: The odds for the home team to win.
            draw: The odds for a draw.
            awayWin: The odds for the away team to win.
        }

    Make sure that the output is a valid JSON array. If the model generates extraneous text, make sure to adjust it. The format is valid JSON.

    Format the result to the following structure:
    \`\`\`json
    [
        {
            "date": "YYYY-MM-DD",
            "time": "HH:MM",
            "homeTeam": "Home Team Name",
            "awayTeam": "Away Team Name",
            "league": "League Name",
            "odds": {
                "homeWin": 2.0,
                "draw": 3.0,
                "awayWin": 4.0
            }
        }
    ]
    \`\`\`
    Here is the request:

    Sport: ${sport}
    Country: ${country}
    Date: ${date}
    League: ${league}
    `;

    const result = await model.generateContent(prompt);
    const response = result.response;

    if (!response.text()) {
      return [];
    }

    const jsonStr = cleanJson(response.text() || "[]");
    const matches: FetchedMatchData[] = JSON.parse(jsonStr);

**Finalizing Robust Parsing**

I'm now satisfied with the `cleanJson` function's ability to handle diverse responses. The focus on extracting the substring between the first '[' and last ']' appears robust and reliable across varied outputs. I am focusing on final testing.
